"""
OrangeTree Global — AI HR Onboarding Assistant (UC3)
Powered by Claude API (Anthropic)
Run: streamlit run uc3_hr_assistant.py
"""

import streamlit as st
import anthropic
import json
import base64
from datetime import datetime

LOGO_B64 = ""
LOGO_HTML = '<img src="data:image/svg+xml;base64,' + LOGO_B64 + '" style="width:100%;max-width:220px;display:block;margin-bottom:4px;">'

st.set_page_config(
    page_title="HR Onboarding Assistant | OrangeTree Global",
    page_icon="🌳",
    layout="wide",
)

st.markdown("""
<style>
    .answer-card {
        background: #f8f9fa;
        border-left: 4px solid #F36621;
        padding: 0.9rem 1.1rem;
        border-radius: 4px;
        margin: 0.5rem 0;
        line-height: 1.7;
    }
    .escalate-box {
        background: #fff3ee;
        border-left: 4px solid #dc3545;
        padding: 0.75rem 1rem;
        border-radius: 4px;
        margin-top: 0.8rem;
    }
    .section-header {
        border-left: 4px solid #F36621;
        padding: 0.3rem 0.8rem;
        background: #fff3ee;
        border-radius: 0 4px 4px 0;
        margin: 1.2rem 0 0.6rem 0;
        font-weight: 600;
    }
</style>
""", unsafe_allow_html=True)

st.markdown(
    f'<img src="data:image/svg+xml;base64,{LOGO_B64}" style="width:280px;max-width:100%;display:block;margin-bottom:12px;">',
    unsafe_allow_html=True
)
st.markdown("## HR Onboarding Assistant")
st.markdown("Upload your HR policy document and let employees ask questions — Claude answers instantly from the document.")
st.divider()

with st.sidebar:
    st.markdown(LOGO_HTML, unsafe_allow_html=True)
    st.markdown("---")
    api_key = st.text_input("Anthropic API Key", type="password", help="Get from console.anthropic.com")
    model = st.selectbox("Model", ["claude-opus-4-8", "claude-sonnet-4-6", "claude-haiku-4-5-20251001"], index=2,
        help="Haiku recommended — fast and cost-effective for Q&A")
    st.markdown("---")
    st.markdown("**Organisation**")
    org_name = st.text_input("Company name", placeholder="e.g. OrangeTree Global")
    st.markdown("---")
    st.markdown("**About this tool**")
    st.info("UC3 of OrangeTree's AI SME Suite. Powered by Claude API.", icon="ℹ️")
    st.caption("Answers are based on your uploaded document only. Not legal advice.")

SENSITIVE_KEYWORDS = ["termination", "fired", "dismissed", "salary dispute", "harassment", "discrimination",
                      "legal", "lawsuit", "complaint", "grievance", "misconduct", "redundancy"]

col_upload, col_chat = st.columns([1, 1], gap="large")

with col_upload:
    st.markdown('<div class="section-header">Step 1 — Upload HR Policy Document</div>', unsafe_allow_html=True)
    st.markdown("Upload your HR handbook, leave policy, onboarding guide, or any internal policy document.")
    uploaded_file = st.file_uploader("Upload document", type=["txt", "md", "pdf"],
        label_visibility="collapsed")

    doc_text = ""
    if uploaded_file:
        if uploaded_file.type == "application/pdf":
            try:
                import pdfplumber
                with pdfplumber.open(uploaded_file) as pdf:
                    doc_text = "\n".join(page.extract_text() or "" for page in pdf.pages)
                st.success(f"PDF loaded: {uploaded_file.name} — {len(doc_text):,} characters extracted")
            except ImportError:
                st.warning("PDF reading requires pdfplumber. Run: pip3 install pdfplumber. For now, paste the text below.")
                doc_text = ""
        else:
            doc_text = uploaded_file.read().decode("utf-8", errors="ignore")
            st.success(f"Loaded: {uploaded_file.name} — {len(doc_text):,} characters")

        with st.expander("Preview document (first 500 characters)"):
            st.text(doc_text[:500] + ("..." if len(doc_text) > 500 else ""))

    st.markdown("---")
    st.markdown("**Or paste your policy text directly**")
    paste_text = st.text_area("Paste policy text", height=200,
        placeholder="Paste your HR policy, leave rules, onboarding checklist, or any internal document here...")
    if paste_text.strip():
        doc_text = paste_text

with col_chat:
    st.markdown('<div class="section-header">Step 2 — Ask an Employee Question</div>', unsafe_allow_html=True)
    st.markdown("Type a question as an employee would ask it.")

    question = st.text_area("Employee question", height=100,
        placeholder="e.g. How many days of casual leave do I get per year?\nWhat is the notice period for resignation?\nHow do I apply for maternity leave?")

    ask_btn = st.button("Get Answer", type="primary", use_container_width=True,
        disabled=(not doc_text.strip() or not question.strip()))

    if not doc_text.strip():
        st.caption("Upload or paste a policy document above to enable this.")

    if ask_btn:
        if not api_key:
            st.error("Enter your Anthropic API key in the sidebar.")
            st.stop()

        is_sensitive = any(kw in question.lower() for kw in SENSITIVE_KEYWORDS)

        with st.spinner("Reading your policy document..."):
            try:
                client = anthropic.Anthropic(api_key=api_key)

                system = f"""You are an HR assistant for {org_name or 'this company'}. 
You answer employee questions ONLY based on the HR policy document provided.
If the answer is not in the document, say so clearly — do not guess.
If the question involves sensitive matters (termination, harassment, legal disputes, salary complaints), 
include the text ESCALATE_TO_HR at the start of your response, then answer what you can from the document.
Be clear, friendly, and concise. Use bullet points where helpful."""

                response = client.messages.create(
                    model=model,
                    max_tokens=1000,
                    system=system,
                    messages=[{
                        "role": "user",
                        "content": f"HR POLICY DOCUMENT:\n{doc_text[:8000]}\n\nEMPLOYEE QUESTION:\n{question}"
                    }]
                )

                answer = response.content[0].text.strip()
                needs_escalation = "ESCALATE_TO_HR" in answer or is_sensitive
                answer_clean = answer.replace("ESCALATE_TO_HR", "").strip()

                st.markdown("**Answer:**")
                st.markdown(f'<div class="answer-card">{answer_clean}</div>', unsafe_allow_html=True)

                if needs_escalation:
                    st.markdown(f"""<div class="escalate-box">
<b>HR Escalation Recommended</b><br>
This question involves a sensitive topic. Please direct the employee to speak with HR directly.
</div>""", unsafe_allow_html=True)

                st.markdown(f"<small style='color:#999'>Answered from: {uploaded_file.name if uploaded_file else 'pasted text'} | {datetime.now().strftime('%H:%M')}</small>", unsafe_allow_html=True)

                if "history" not in st.session_state:
                    st.session_state["history"] = []
                st.session_state["history"].append({"q": question, "a": answer_clean, "escalate": needs_escalation})

            except Exception as e:
                st.error(f"Error: {e}")

if st.session_state.get("history"):
    st.divider()
    st.markdown("**Previous questions this session**")
    for i, item in enumerate(reversed(st.session_state["history"][-5:]), 1):
        with st.expander(f"Q: {item['q'][:80]}{'...' if len(item['q']) > 80 else ''}"):
            st.write(item["a"])
            if item["escalate"]:
                st.warning("HR escalation was recommended for this question.")

st.caption("OrangeTree Global | AI SME Suite — UC3: HR Onboarding Assistant")
